from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json"}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}
    with open(slack_path) as f:
        data = json.load(f)
    channels = data.get("channels", {})
    messages = data.get("messages", {})

    def find_channel_id(target_name):
        for cid, cinfo in channels.items():
            name = cinfo.get("name", "").lower().replace("_", "-")
            if target_name.lower().replace("_", "-") in name:
                return cid
        return None

    def msg_matches(text):
        # Accept TexPal or TexPal Logistics, case insensitive
        pattern = r'^urgent:\s*issue with texpal(\s+logistics)?\s+for\s+shipment\s+received\s+on\s+2026-04-01$'
        return bool(re.match(pattern, text.strip(), re.IGNORECASE))

    results = {}
    for channel_name in ["cold-chain-alerts", "dc-escalations-houston"]:
        cid = find_channel_id(channel_name)
        if cid is None:
            results[channel_name] = f"Channel #{channel_name} not found"
            continue
        channel_msgs = messages.get(cid, [])
        found = False
        for msg in channel_msgs:
            text = msg.get("text", "")
            if msg_matches(text):
                found = True
                break
        if not found:
            texts = [m.get("text", "") for m in channel_msgs]
            results[channel_name] = f"No matching URGENT TexPal message found. Messages: {texts}"
        else:
            results[channel_name] = "OK"

    all_pass = all(v == "OK" for v in results.values())
    if all_pass:
        return {"pass": True, "score": 1.0, "feedback": "Found URGENT TexPal shipment messages in both #cold-chain-alerts and #dc-escalations-houston"}
    else:
        feedback = "; ".join(f"{k}: {v}" for k, v in results.items())
        return {"pass": False, "score": 0.0, "feedback": feedback}

