from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)
    # Find all files starting with IR (case insensitive)
    ir_files = [f for f in workspace.glob("*") if f.is_file() and f.name.upper().startswith("IR")]
    if len(ir_files) == 0:
        return {"pass": False, "score": 0.0, "feedback": "No file with 'IR' prefix found in workspace"}
    if len(ir_files) > 1:
        return {"pass": False, "score": 0.3, "feedback": f"Multiple IR-prefixed files found: {[f.name for f in ir_files]}. Expected exactly one."}
    ir_file = ir_files[0]
    if "2026-04-01" not in ir_file.name or "contamination" not in ir_file.name.lower():
        return {"pass": False, "score": 0.3, "feedback": f"IR file found as '{ir_file.name}' but expected name to contain '2026-04-01' and 'Contamination'"}
    if ir_file.suffix.lower() != ".pdf":
        return {"pass": False, "score": 0.3, "feedback": f"IR file '{ir_file.name}' is not a PDF"}
    # Check PDF content
    try:
        import pdfplumber
        with pdfplumber.open(ir_file) as pdf:
            text = ""
            for page in pdf.pages:
                text += (page.extract_text() or "")
    except Exception as ex:
        return {"pass": False, "score": 0.3, "feedback": f"Could not read PDF '{ir_file.name}': {ex}"}
    text_lower = text.lower()
    checks = {
        "Incident Date 2026-04-01": "2026-04-01" in text,
        "Incident Category Contamination": "contamination" in text_lower,
        "Priority Level P1": bool(re.search(r'p1|priority.*1|1.*priority', text_lower))
    }
    all_ok = all(checks.values())
    if all_ok:
        return {"pass": True, "score": 1.0, "feedback": f"IR file '{ir_file.name}' exists with correct content: date 2026-04-01, Contamination, P1"}
    failed = [k for k, v in checks.items() if not v]
    return {"pass": False, "score": 0.5, "feedback": f"IR file '{ir_file.name}' exists but missing content: {failed}. Extracted text snippet: {text[:500]}"}

