    # Find the original server update email's message_id
    original_msg_id = None
    for e in emails:
        subject = e.get("subject", "") or ""
        from_addr = e.get("from_addr", "") or ""
        if "upcoming server update" in subject.lower() and "hannah.brooks@prairiestar.com" in from_addr.lower():
            original_msg_id = e.get("message_id", "")
            break
    # Check no sent email replies to or forwards this email
    sent_emails = [e for e in emails if e.get("folder", "").lower() == "sent"]
    for e in sent_emails:
        subject = (e.get("subject", "") or "").lower()
        in_reply_to = (e.get("in_reply_to", "") or "").lower()
        # Check if it's a reply by in_reply_to field matching original message_id
        if original_msg_id and in_reply_to and original_msg_id.lower() in in_reply_to:
            return {"pass": False, "score": 0.0, "feedback": f"Found a reply/forward to the 'Upcoming Server Update' email (via in_reply_to): '{e.get('subject', '')}'"}
        # Check if subject looks like a reply or forward referencing server update
        if "server update" in subject:
            if "re:" in subject or "fw:" in subject or "fwd:" in subject:
                return {"pass": False, "score": 0.0, "feedback": f"Found what appears to be a reply/forward to 'Upcoming Server Update' email: '{e.get('subject', '')}'"}
            # Also catch cases where in_reply_to is set even without re:/fw: prefix
            if e.get("in_reply_to"):
                return {"pass": False, "score": 0.0, "feedback": f"Found what appears to be a reply to 'Upcoming Server Update' email (has in_reply_to set): '{e.get('subject', '')}'"}
        # Also check if subject contains 'upcoming server update' with forward prefix
        if "upcoming server update" in subject:
            if "fw:" in subject or "fwd:" in subject or "re:" in subject:
                return {"pass": False, "score": 0.0, "feedback": f"Found a reply/forward referencing 'Upcoming Server Update': '{e.get('subject', '')}'"}
