    with open(slack_path) as f:
        data = json.load(f)
    messages = data.get("messages", {})
    total = 0
    channel_counts = {}
    for channel_id, msgs in messages.items():
        count = len(msgs)
        total += count
        # Get channel name for feedback
        channels = data.get("channels", {})
        ch_name = channels.get(channel_id, {}).get("name", channel_id)
        channel_counts[ch_name] = count
    if total == 11:
        return {"pass": True, "score": 1.0, "feedback": f"Found exactly 11 messages total across channels: {channel_counts}"}
    return {"pass": False, "score": 0.0, "feedback": f"Expected 11 total messages but found {total}. Per channel: {channel_counts}"}
